class Solution:
    def minCostConnectPoints(self, points: list[list[int]]) -> int:
        import heapq
        n = len(points)
        visited = set()
        min_heap = [(0, 0)]  # (cost, point_index)
        total_cost = 0

        while len(visited) < n:
            cost, i = heapq.heappop(min_heap)
            if i in visited:
                continue
            visited.add(i)
            total_cost += cost

            # Add edges to all unvisited neighbors
            for j in range(n):
                if j not in visited:
                    dist = abs(points[i][0] - points[j][0]) + abs(points[i][1] - points[j][1])
                    heapq.heappush(min_heap, (dist, j))

        return total_cost

class Solution:
    def minCostConnectPoints(self, points: list[list[int]]) -> int:
        n = len(points)
        # Generate all edges with their costs
        edges = []
        for i in range(n):
            for j in range(i + 1, n):
                dist = abs(points[i][0] - points[j][0]) + abs(points[i][1] - points[j][1])
                edges.append((dist, i, j))

        # Sort edges by cost
        edges.sort()

        # Union-Find
        parent = list(range(n))
        def find(x):
            if parent[x] != x:
                parent[x] = find(parent[x])  # path compression
            return parent[x]

        def union(x, y):
            px, py = find(x), find(y)
            if px == py:
                return False  # already connected
            parent[px] = py
            return True

        # Kruskal's: add edges that don't create a cycle
        total_cost = 0
        edges_added = 0
        for cost, u, v in edges:
            if union(u, v):
                total_cost += cost
                edges_added += 1
                if edges_added == n - 1:  # MST complete
                    break

        return total_cost

class Solution:
    def networkDelayTime(self, times: list[list[int]], n: int, k: int) -> int:
        import heapq
        from collections import defaultdict
        # Build adjacency list
        graph = defaultdict(list)
        for u, v, w in times:
            graph[u].append((v, w))  # (neighbor, weight)

        # Dijkstra
        dist = {i: float('inf') for i in range(1, n + 1)}
        dist[k] = 0
        min_heap = [(0, k)]  # (time, node)

        while min_heap:
            time, node = heapq.heappop(min_heap)
            if time > dist[node]:  # already found a better path
                continue
            for neighbor, weight in graph[node]:
                new_time = time + weight
                if new_time < dist[neighbor]:
                    dist[neighbor] = new_time
                    heapq.heappush(min_heap, (new_time, neighbor))

        max_time = max(dist.values())
        return max_time if max_time < float('inf') else -1

class Solution:
    def networkDelayTime(self, times: list[list[int]], n: int, k: int) -> int:
        # Initialize distances
        dist = [float('inf')] * (n + 1)
        dist[k] = 0

        # Relax all edges n-1 times
        for _ in range(n - 1):
            for u, v, w in times:
                if dist[u] != float('inf') and dist[u] + w < dist[v]:
                    dist[v] = dist[u] + w

        # Find max distance (excluding index 0)
        max_time = max(dist[1:])
        return max_time if max_time < float('inf') else -1

class Solution:
    def findCheapestPrice(self, n: int, flights: list[list[int]], src: int, dst: int, k: int) -> int:
        # Initialize distances
        dist = [float('inf')] * n
        dist[src] = 0

        # Relax edges k+1 times (k stops = k+1 edges)
        for _ in range(k + 1):
            temp = dist[:]
            for u, v, price in flights:
                if dist[u] != float('inf'):
                    temp[v] = min(temp[v], dist[u] + price)
            dist = temp

        return dist[dst] if dist[dst] != float('inf') else -1

class Solution:
    def findCheapestPrice(self, n: int, flights: list[list[int]], src: int, dst: int, k: int) -> int:
        import heapq
        from collections import defaultdict
        # Build adjacency list
        graph = defaultdict(list)
        for u, v, price in flights:
            graph[u].append((v, price))

        # (cost, node, stops_used)
        min_heap = [(0, src, 0)]
        # Track best cost to reach each node with at most s stops
        best = {}

        while min_heap:
            cost, node, stops = heapq.heappop(min_heap)
            if node == dst:
                return cost
            if stops > k:  # exceeded stop limit
                continue
            if (node, stops) in best and best[(node, stops)] <= cost:
                continue  # already found a better path with same stops
            best[(node, stops)] = cost

            for neighbor, price in graph[node]:
                heapq.heappush(min_heap, (cost + price, neighbor, stops + 1))

        return -1

class Solution:
    def findItinerary(self, tickets: list[list[str]]) -> list[str]:
        from collections import defaultdict
        # Build adjacency list, sorted for lexicographical order
        graph = defaultdict(list)
        for src, dst in sorted(tickets, reverse=True):
            graph[src].append(dst)

        route = []
        def dfs(airport):
            while graph[airport]:
                next_dest = graph[airport].pop()  # remove edge
                dfs(next_dest)
            route.append(airport)  # postorder — add after exhausting edges

        dfs('JFK')
        return route[::-1]  # reverse to get forward path

class Solution:
    def swimInWater(self, grid: list[list[int]]) -> int:
        import heapq
        n = len(grid)
        visited = set()
        min_heap = [(grid[0][0], 0, 0)]  # (max_elevation, row, col)
        directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]

        while min_heap:
            max_elev, r, c = heapq.heappop(min_heap)
            if (r, c) in visited:
                continue
            visited.add((r, c))

            if r == n - 1 and c == n - 1:  # reached bottom-right
                return max_elev

            for dr, dc in directions:
                nr, nc = r + dr, c + dc
                if 0 <= nr < n and 0 <= nc < n and (nr, nc) not in visited:
                    heapq.heappush(min_heap, (max(max_elev, grid[nr][nc]), nr, nc))

        return -1  # should never reach here

class Solution:
    def swimInWater(self, grid: list[list[int]]) -> int:
        n = len(grid)

        def can_reach(time):
            # DFS to check if we can reach bottom-right with max elevation <= time
            if grid[0][0] > time:
                return False
            visited = set()
            stack = [(0, 0)]
            directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]

            while stack:
                r, c = stack.pop()
                if (r, c) in visited:
                    continue
                visited.add((r, c))

                if r == n - 1 and c == n - 1:
                    return True

                for dr, dc in directions:
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < n and 0 <= nc < n and (nr, nc) not in visited and grid[nr][nc] <= time:
                        stack.append((nr, nc))

            return False

        # Binary search on the time
        left, right = grid[0][0], n * n - 1
        while left < right:
            mid = (left + right) // 2
            if can_reach(mid):
                right = mid
            else:
                left = mid + 1

        return left

class Solution:
    def swimInWater(self, grid: list[list[int]]) -> int:
        n = len(grid)
        # Create list of (elevation, row, col)
        cells = []
        for r in range(n):
            for c in range(n):
                cells.append((grid[r][c], r, c))
        cells.sort()  # process cells in increasing elevation order

        # Union-Find
        parent = {}
        def find(x):
            if x not in parent:
                parent[x] = x
            if parent[x] != x:
                parent[x] = find(parent[x])
            return parent[x]

        def union(x, y):
            px, py = find(x), find(y)
            if px != py:
                parent[px] = py

        directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]
        for elev, r, c in cells:
            # Union this cell with adjacent cells that have been processed
            for dr, dc in directions:
                nr, nc = r + dr, c + dc
                if 0 <= nr < n and 0 <= nc < n and (nr, nc) in parent:
                    union((r, c), (nr, nc))

            # Check if start and end are connected
            if find((0, 0)) == find((n - 1, n - 1)):
                return elev

        return -1

class Solution:
    def alienOrder(self, words: list[str]) -> str:
        from collections import defaultdict
        # Initialize graph with all unique characters
        graph = {c: set() for word in words for c in word}

        # Build edges from adjacent word pairs
        for i in range(len(words) - 1):
            w1, w2 = words[i], words[i + 1]
            min_len = min(len(w1), len(w2))
            # Edge case: if w1 is a prefix and longer, invalid
            if len(w1) > len(w2) and w1[:min_len] == w2[:min_len]:
                return ''
            for j in range(min_len):
                if w1[j] != w2[j]:
                    graph[w1[j]].add(w2[j])
                    break

        # DFS-based topological sort with cycle detection
        visited = {}  # False = visiting, True = visited
        result = []

        def dfs(char):
            if char in visited:
                return visited[char]  # True if already done, False if cycle
            visited[char] = False  # mark as visiting
            for neighbor in graph[char]:
                if not dfs(neighbor):  # cycle detected
                    return False
            visited[char] = True  # mark as visited
            result.append(char)  # postorder
            return True

        for char in graph:
            if not dfs(char):
                return ''  # cycle detected

        return ''.join(result[::-1])  # reverse postorder for topo sort

class Solution:
    def alienOrder(self, words: list[str]) -> str:
        from collections import defaultdict, deque
        # Initialize graph and in-degrees
        graph = {c: set() for word in words for c in word}
        in_degree = {c: 0 for word in words for c in word}

        # Build edges from adjacent word pairs
        for i in range(len(words) - 1):
            w1, w2 = words[i], words[i + 1]
            min_len = min(len(w1), len(w2))
            # Edge case: if w1 is a prefix and longer, invalid
            if len(w1) > len(w2) and w1[:min_len] == w2[:min_len]:
                return ''
            for j in range(min_len):
                if w1[j] != w2[j]:
                    if w2[j] not in graph[w1[j]]:  # avoid duplicate edges
                        graph[w1[j]].add(w2[j])
                        in_degree[w2[j]] += 1
                    break

        # BFS topological sort (Kahn's algorithm)
        queue = deque([c for c in in_degree if in_degree[c] == 0])
        result = []

        while queue:
            char = queue.popleft()
            result.append(char)
            for neighbor in graph[char]:
                in_degree[neighbor] -= 1
                if in_degree[neighbor] == 0:
                    queue.append(neighbor)

        # If not all characters processed, there's a cycle
        if len(result) != len(in_degree):
            return ''

        return ''.join(result)
